  "bug_fixes": {
    "bug_1": {
      "description": "wave_status query used AND + multiple eq() instead of inArray",
      "impact": "SQL WHERE task_id='a' AND task_id='b' can never match >1 row; runningClaims was always empty",
      "fix": "Replaced ...group.task_ids.map(tid => eq(CoordinationClaimTable.task_id, tid)) with inArray(CoordinationClaimTable.task_id, group.task_ids)"
    },
    "bug_2": {
      "description": "claimTask appends task_id to fan-out task_ids without dedup",
      "impact": "Retries inflate task_ids array, skewing complete_count ratios",
      "fix": "Added existing.task_ids.includes(taskId) check before appending"
    },
    "bug_3": {
      "description": "Path reservations persist forever when worker crashes",
      "impact": "Stale reservations block other workers from claiming paths",
      "fix": "Added 5-minute stale detection (300_000ms) in checkPathReserved, reservePath, and reservations tool query; stale reservations are auto-released when detected"
    },
    "bug_4": {
      "description": "formatStructuredResult interpolates user-controlled fields raw into XML output",
      "impact": "Fields containing \", >, <, & produce malformed XML or prompt-injection vectors",
      "fix": "Added escapeXml() helper replacing &, <, >, \", ' with XML entities; applied to claim.taskId, status, description, subagentType, waveType, result, error"
    }
  },
  "lessons": ["smart_sd tool reports 'applied' but may not actually write; always verify with separate read"],
  "recommendation": "merge"
}

